Office.onReady(() => {});

function onMessageSendHandler(event) {

    const trustedDomains = [
        "@sg.moomoo.com"
    ];

    const item = Office.context.mailbox.item;

    item.to.getAsync(function(toResult) {

        item.cc.getAsync(function(ccResult) {

            item.bcc.getAsync(function(bccResult) {

                let recipients = [];

                if (toResult.status === Office.AsyncResultStatus.Succeeded) {
                    recipients = recipients.concat(toResult.value);
                }

                if (ccResult.status === Office.AsyncResultStatus.Succeeded) {
                    recipients = recipients.concat(ccResult.value);
                }

                if (bccResult.status === Office.AsyncResultStatus.Succeeded) {
                    recipients = recipients.concat(bccResult.value);
                }

                let externalFound = false;

                recipients.forEach(r => {

                    const email = r.emailAddress.toLowerCase();

                    let trusted = false;

                    trustedDomains.forEach(domain => {

                        if (email.endsWith(domain)) {
                            trusted = true;
                        }

                    });

                    if (!trusted) {
                        externalFound = true;
                    }

                });

                if (externalFound) {

                    event.completed({
                        allowEvent: false,
                        errorMessage:
                        "External recipient detected. Please review recipients before sending."
                    });

                } else {

                    event.completed({
                        allowEvent: true
                    });

                }

            });

        });

    });

}

Office.actions.associate("onMessageSendHandler", onMessageSendHandler);